mapper.select:
SELECT trip_id, party_id, creator_id, title, description, start_date, end_date, created_at, updated_at
FROM trip
WHERE trip_id = #{tripId}

mapper.update:
UPDATE trip
SET     title = #{title},
        description = #{description},
        start_date = #{startDate},
        end_date = #{endDate}
WHERE trip_id = #{tripId}
